async (page) => {
  // Emergency warp - skip combat cooldown, use direct warp
  await page.evaluate(() => {
    try { window.__clearCombatState(); } catch(e) {}
    try { window.game.menu.warp.show(); } catch(e) {}
  });
  await page.waitForTimeout(500);
  await page.evaluate(() => { const b = document.getElementById('warp0'); if(b) b.click(); });
  await page.waitForTimeout(4000);
  const state = await page.evaluate(() => {
    if (typeof window.__latestGameState === 'undefined') return JSON.stringify({error:'disconnected'});
    return JSON.stringify(window.__latestGameState);
  });
  const parsed = JSON.parse(state);
  if (parsed.error) return JSON.stringify(parsed);
  return JSON.stringify({ pos: parsed.player_position, hp: parsed.player_stats, is_dead: parsed.ui_state?.is_dead });
}

async (page) => {
  await page.waitForTimeout(5000); // let nav complete
  const result = await page.evaluate((name) => JSON.stringify(window.__interactNPC(name)), 'Bubba');
  await page.waitForTimeout(2000);
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  return JSON.stringify({ interact: result, pos: parsed.player_position, dialogue: parsed.ui_state?.npc_dialogue, quest_panel: parsed.ui_state?.quest_panel_visible });
}

async (page) => {
  await page.evaluate(({x,y}) => window.__moveTo(x,y), {x:122, y:231});
  await page.waitForTimeout(2000);
  const result = await page.evaluate((id) => JSON.stringify(window.__talkToNPC(id)), '1-79101828');
  await page.waitForTimeout(1500);
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  return JSON.stringify({ talk: result, pos: parsed.player_position, dialogue: parsed.ui_state?.npc_dialogue });
}
